SELECT

FROM
    rdp_blob_resource
WHERE
    instance_id = #{instanceId}
    AND
    owner_type = #{resourceType,javaType=com.clougence.clouddm.base.metadata.rdp.enumeration.ResourceType}
    AND
    blob_type = #{fileType,javaType=com.clougence.clouddm.base.metadata.rdp.enumeration.SecurityFileType}

